checker_dsl:
EXISTS (`method call MC`) {
  EXISTS (`data flow node SINK`) {
    AND {
      (`MC is a call to method M named "getName"`),
      EXISTS (`reference type RT`) {
        AND {
          (`RT is an ancestor of the declaring type of M`),
          OR {
            (`RT has qualified name "java.util.zip.ZipEntry"`),
            (`RT has qualified name "org.apache.commons.compress.archivers.ArchiveEntry"`)
          }
        }
      },
      NOT {
        EXISTS (`data flow node BARRIER`) {
          AND {
            OR {
              (`BARRIER is a SimpleTypeSanitizer`),
              (`BARRIER is a PathInjectionSanitizer`)
            }
          }
        }
      }
    }
  }
}
